function cumRet(key, startYear, n) {
  const d = ANNUAL[key]; if (!d) return null;
  let c = 1;
  for (let y = startYear; y < startYear + n; y++) { if (d[y] === undefined) return null; c *= 1 + d[y]/100; }
  return parseFloat(((c-1)*100).toFixed(2));
}
function applySegment(ir, gt, cap, par, useCap, pt, pl, trigRate) {
  // Dual Direction Trigger: any positive OR negative within buffer → flat trigger rate
  if (gt === "dual-trigger") {
    if (ir >= 0) return trigRate;
    if (ir >= -pl) return trigRate;  // within buffer, get trigger rate
    return ir + pl;                   // beyond buffer, absorb loss past buffer
  }
  // Dual Direction: positive → cap, negative within buffer → abs value credited
  if (gt === "dual") {
    if (ir >= 0) return Math.min(ir, cap);
    if (ir >= -pl) return Math.abs(ir); // within buffer, credit the positive equivalent
    return ir + pl;                      // beyond buffer, absorb loss past buffer
  }
  // Trigger: any positive → flat trigger rate; negative → standard buffer protection
  if (gt === "trigger") {
    if (ir >= 0) return trigRate;
    return pt === "buffer" ? (ir < -pl ? ir + pl : 0) : Math.max(ir, -pl);
  }
  // Standard
  if (ir >= 0) {
    if (gt === "cap") return Math.min(ir, cap);
    const g = ir*(par/100); return useCap ? Math.min(g, cap) : g;
  }
  return pt === "buffer" ? (ir < -pl ? ir+pl : 0) : Math.max(ir, -pl);
}
const IDX_NAME = {sp:"S&P 500",rus:"Russell 2000",eafe:"MSCI EAFE"};
function blendRet(startYear, term) {
  const keys = ["sp","rus","eafe"];
  const rets = keys.map(k => ({key:k, ret:cumRet(k, startYear, term)})).filter(x=>x.ret!==null);
  if (rets.length < 3) return null;
  rets.sort((a,b)=>b.ret-a.ret);
  const weights = [0.50, 0.30, 0.20];
  const blended = parseFloat((rets[0].ret*0.50 + rets[1].ret*0.30 + rets[2].ret*0.20).toFixed(2));
  return {
    ret: blended,
    breakdown: rets.slice(0,3).map((r,i)=>({name:IDX_NAME[r.key], ret:r.ret, weight:weights[i]})),
  };
}
function computeSegments(alloc, startYear) {
  const key = IDX_KEY[alloc.index];
  const annualFee = (alloc.feeOn && alloc.fee > 0) ? alloc.fee : 0;
  const segs = []; let y = startYear;
  while (y < startYear + 6) {
    const t = alloc.term, endY = Math.min(y+t-1, startYear+5), actualT = endY-y+1;
    const blendData = alloc.index==="Performance Blend" ? blendRet(y, actualT) : null;
    const ir = blendData ? blendData.ret : cumRet(key, y, actualT);
    const creditGross = ir !== null ? parseFloat(applySegment(ir, alloc.growthType, alloc.capRate, alloc.parRate, alloc.useCapOnPar, alloc.protType, alloc.protLvl, alloc.trigRate||0).toFixed(2)) : null;
    // Apply fee annually: compound gross return net of annual fee over segment term
    let creditNet = creditGross;
    if (creditGross !== null && annualFee > 0) {
      const grossFactor = 1 + creditGross / 100;
      // annualize gross, subtract fee each year, recompound over segment term
      const annualGross = Math.pow(grossFactor, 1 / actualT) - 1;
      const annualNet = annualGross - annualFee / 100;
      creditNet = parseFloat(((Math.pow(1 + annualNet, actualT) - 1) * 100).toFixed(2));
    }
    segs.push({startY:y, endY, indexRaw:ir, credit:creditGross, creditNet, term:actualT, blendBreakdown:blendData?.breakdown||null});
    y += t;
  }
  return segs;
}
function cumAgg(startYear, term) {
  let c = 1;
  for (let y = startYear; y < startYear + term; y++) {
    if (ANNUAL.agg[y] === undefined) return null;
    c *= 1 + ANNUAL.agg[y] / 100;
  }
  return parseFloat(((c - 1) * 100).toFixed(2));
}
function cum6040(startYear, term, eqPct, annualFee) {
  // eqPct% S&P 500 price return, (100-eqPct)% US Agg total return — rebalanced annually
  const eq = (eqPct||60) / 100;
  const bd = 1 - eq;
  const fee = (annualFee||0) / 100;
  let c = 1;
  for (let y = startYear; y < startYear + term; y++) {
    const sp = ANNUAL.sp[y]; const ag = ANNUAL.agg[y];
    if (sp === undefined || ag === undefined) return null;
    c *= (1 + (sp * eq + ag * bd) / 100) * (1 - fee);
  }
  return parseFloat(((c - 1) * 100).toFixed(2));
}
function portfolioResult(allocations, startYear) {
  const tot = allocations.reduce((s,a)=>s+(a.pct||0),0);
  if (!tot) return null;
  let wRilaGross=0, wRilaNet=0, wRaw=0;
  for (const a of allocations) {
    const segs = computeSegments(a, startYear);
    let rCumGross=1, rCumNet=1, rawCum=1;
    for (const sg of segs) {
      if (sg.credit!==null) rCumGross *= 1+sg.credit/100;
      if (sg.creditNet!==null) rCumNet *= 1+sg.creditNet/100;
      if (sg.indexRaw!==null) rawCum *= 1+sg.indexRaw/100;
    }
    const w = a.pct/tot;
    wRilaGross += (rCumGross-1)*100*w;
    wRilaNet   += (rCumNet-1)*100*w;
    wRaw       += (rawCum-1)*100*w;
  }
  return {
    rila: parseFloat(wRilaGross.toFixed(2)),
    rilaNet: parseFloat(wRilaNet.toFixed(2)),
    raw: parseFloat(wRaw.toFixed(2))
  };
}

function clr(v) { return v >= 0 ? "#16A34A" : "#DC2626"; }
function fmt(v, d=1) { return (v>=0?"+":"")+v.toFixed(d)+"%" }
function fmtD(v) { return (v>=0?"+$":"-$")+Math.abs(v).toLocaleString("en-US",{maximumFractionDigits:0}); }

// ─── Animated counter ────────────────────────────────────────────────────
function Counter({ target, prefix="", suffix="", duration=1200, color="#000", size=40 }) {
  const [val, setVal] = useState(0);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    let start = null, from = 0;
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts-start)/duration, 1);
      const ease = 1-Math.pow(1-p,3);
      setVal(from + (target-from)*ease);
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [target]);
  return <span style={{fontSize:size,fontWeight:800,color,letterSpacing:"-0.02em"}}>{prefix}{Math.abs(val).toFixed(1)}{suffix}</span>;
}

// ─── Segment bar ─────────────────────────────────────────────────────────
function SegmentBar({ raw, credit, color }) {
  const max = Math.max(Math.abs(raw??0), Math.abs(credit??0), 5);
  const rawPct = Math.min(100, (Math.abs(raw??0)/max)*100);
  const credPct = Math.min(100, (Math.abs(credit??0)/max)*100);
  return (
    <div style={{display:"flex",flexDirection:"column",gap:3}}>
      <div style={{display:"flex",alignItems:"center",gap:6}}>
        <span style={{fontSize:9,color:SLATE,width:42,textAlign:"right"}}>Raw</span>
        <div style={{flex:1,height:7,background:"#F1F5F9",borderRadius:4,overflow:"hidden"}}>
          <div style={{width:`${rawPct}%`,height:"100%",background:(raw??0)>=0?"#CBD5E1":"#FCA5A5",borderRadius:4}}/>
        </div>
        <span style={{fontSize:10,color:clr(raw??0),fontWeight:600,width:46,textAlign:"right"}}>{raw!==null?fmt(raw,0):"—"}</span>
      </div>
      <div style={{display:"flex",alignItems:"center",gap:6}}>
        <span style={{fontSize:9,color:SLATE,width:42,textAlign:"right"}}>Credited</span>
        <div style={{flex:1,height:7,background:"#F1F5F9",borderRadius:4,overflow:"hidden"}}>
          <div style={{width:`${credPct}%`,height:"100%",background:(credit??0)>=0?color:"#DC2626",borderRadius:4}}/>
        </div>
        <span style={{fontSize:10,color:clr(credit??0),fontWeight:700,width:46,textAlign:"right"}}>{credit!==null?fmt(credit,0):"—"}</span>
      </div>
    </div>
  );
}

