            origin:"Created in 1969 by Capital International, before Morgan Stanley acquired the business and renamed it MSCI. It remains the most widely used benchmark for non-U.S. developed market equities.",
            funFact:"The MSCI EAFE Index has tracked returns for over 50 years and is the benchmark for roughly $3.7 trillion in assets globally. Japan alone represents more than 20% of the index — more than any other single country.",
            what:"Covers large and mid-cap equity performance across 21 developed-market countries in Europe, Australasia, and the Far East — explicitly excluding the United States and Canada. Returns are expressed in U.S. dollars, meaning currency movements affect performance for American investors.",
            avg:"~5.5% per year, 1986–2025 (USD terms)",
            risk:"Moderate", vol:"~17% annualized",
            best:"+39% (2003)", worst:"-43% (2008)", posYears:"~68% of calendar years",
            holdings:[["Novo Nordisk","NVO"],["ASML","ASML"],["Nestlé","NESN"],["LVMH","MC"],["Schneider Electric","SU"]],
            sectors:[["Financials","21"],["Industrials","16"],["Healthcare","13"],["Consumer Disc.","12"],["Info Technology","9"]],
            countries:"Japan ~22% · UK ~14% · France ~12% · Switzerland ~10% · Germany ~9%",
